pub(crate) trait Completable {
    type Output;
    fn complete(self, cqe: CqeResult) -> Self::Output;

    // This is used when you want to terminate an operation with an error.
    //
    // The `Op` type that implements this trait can return the passed error
    // upstream by embedding it in the `Output`.
    fn complete_with_error(self, error: Error) -> Self::Output;
}

if parent.children.len() == pos + 1 {
    parent.children.pop().unwrap();
} else {
    // If `node` is not the last element in the list, we need to
    // replace it with the last element
    let replacement_child = parent.children.pop().unwrap();
    replacement_child.inner.lock().unwrap().parent_idx = pos;
    parent.children[pos] = replacement_child;
}

for yak in 1..=yaks {
    let res = shave(yak);
    debug!(target: "yak_events", yak, shaved = res.is_ok());

    if let Err(ref error) = res {
        // Like spans, events can also use the field initialization shorthand.
        // In this instance, `yak` is the field being initalized.
        error!(yak, error = error.as_ref(), "failed to shave yak");
    } else {
        yaks_shaved += 1;
    }
    trace!(yaks_shaved);
}

if let Some(location) = panic.location() {
    // On nightly Rust, where the `PanicInfo` type also exposes a
    // `message()` method returning just the message, we could record
    // just the message instead of the entire `fmt::Display`
    // implementation, avoiding the duplicated location
    tracing::error!(
        message = %panic,
        panic.file = location.file(),
        panic.line = location.line(),
        panic.column = location.column(),
    );
} else {
    tracing::error!(message = %panic);
}

